import{_ as e,c as i,a,o as n}from"./app-CEcM0piI.js";const l={};function d(t,s){return n(),i("div",null,s[0]||(s[0]=[a(`<p>JavaScript（简称：JS）是一门跨平台、面向对象的脚本语言。是用来控制网页行为的，它能使网页可交互。</p><h1 id="引入方式" tabindex="-1"><a class="header-anchor" href="#引入方式"><span>引入方式</span></a></h1><h2 id="内部脚本" tabindex="-1"><a class="header-anchor" href="#内部脚本"><span>内部脚本</span></a></h2><p>内部脚本：将JS代码定义在HTML页面中JavaScript代码必须位于&lt;script&gt;&lt;/script&gt;标签之间 在HTML文档中，可以在任意地方，放置任意数量的&lt;script&gt; 一般会把脚本置于&lt;body&gt;元素的底部，可改善显示速度</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;script&gt;</span></span>
<span class="line"><span>	alert(&quot;Hello JavaScript&quot;)</span></span>
<span class="line"><span>	&lt;/script&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="外部脚本" tabindex="-1"><a class="header-anchor" href="#外部脚本"><span>外部脚本</span></a></h2><p>外部脚本：将JS代码定义在外部JS文件中，然后引入到HTML页面中 外部JS文件中，只包含JS代码，不包含&lt;script&gt;标签 &lt;script&gt;标签不能自闭合(即必须有开始结束两个标签,有的html标签即使没有结束标签也会生效:自闭合,但&lt;script&gt;标签不行)</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;script src=&quot;js/demo.js&quot;&gt;&lt;/script&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h1 id="语法" tabindex="-1"><a class="header-anchor" href="#语法"><span>语法</span></a></h1><p>语句末尾的分号可写可不写,建议写上</p><p><strong>注释和java一样</strong></p><h3 id="输出语句" tabindex="-1"><a class="header-anchor" href="#输出语句"><span>输出语句</span></a></h3><h5 id="将输出内容写入警告框" tabindex="-1"><a class="header-anchor" href="#将输出内容写入警告框"><span>将输出内容写入警告框</span></a></h5><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>window.alert(string s)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h5 id="写入html输出" tabindex="-1"><a class="header-anchor" href="#写入html输出"><span>写入HTML输出</span></a></h5><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>document.write(string s)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h5 id="写入浏览器控制台" tabindex="-1"><a class="header-anchor" href="#写入浏览器控制台"><span>写入浏览器控制台</span></a></h5><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>console.log(string s)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h1 id="声明变量" tabindex="-1"><a class="header-anchor" href="#声明变量"><span>声明变量</span></a></h1><h4 id="var" tabindex="-1"><a class="header-anchor" href="#var"><span>var</span></a></h4><p>JavaScript中用var关键字（variable的缩写）来声明变量 JavaScript是一门弱类型语言，变量可以存放不同类型的值</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>var a=20;</span></span>
<span class="line"><span>a=&quot;张三&quot;;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>特点:</p><ol><li>使用var定义的作用域比较大，是全局变量,即使出了作用域符<code>{}</code>也还是可以使用</li><li>可以重复定义. 可以在定义一个变量后再定义一个同名变量,后定义的会覆盖先定义的</li></ol><h4 id="let" tabindex="-1"><a class="header-anchor" href="#let"><span>let</span></a></h4><p>ECMAScript6新增了let关键字来定义变量。它的用法类似于var，但是所声明的变量，只在let关键字所在的代码块内有效，且不允许重复声明。</p><h4 id="const" tabindex="-1"><a class="header-anchor" href="#const"><span>const</span></a></h4><p>ECMAScript6新增了const关键字，用来声明一个只读的常量。一旦声明，常量的值就不能改变。</p><p><strong>变量在函数内不声明直接赋值则是全局变量</strong></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>function fn(){</span></span>
<span class="line"><span>	num=10</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span>fn()</span></span>
<span class="line"><span>console.log(num)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h1 id="数据类型" tabindex="-1"><a class="header-anchor" href="#数据类型"><span>数据类型</span></a></h1><ul><li>number：数字（整数、小数、NaN(NotaNumber)）</li><li>string：字符串，单双引皆可</li><li>boolean:布尔。true，false</li><li>null：对象为空</li><li>undefined: 当声明的变量未初始化时，该变量的默认值是undefined</li></ul><p><strong>使用typeof运算符可以获取数据类型</strong></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>vara=20;</span></span>
<span class="line"><span>alert(typeof a);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>typeof运算符对于null值会返回&quot;Object&quot;。这实际上是JavaScript最初实现中的一个错误，然后被ECMAScript沿用了。现在，null被认为是对象的占位符，从而解释了这一矛盾，但从技术上来说，它仍然是原始值。</p><h3 id="运算符" tabindex="-1"><a class="header-anchor" href="#运算符"><span>运算符</span></a></h3><p>大部分运算符和java一样,但多了一个===全等运算符</p><p>使用==运算符在判断两个值是否相等时会先判断他们的类型是否相同,如果不相同就先进行类型转换然后再比较</p><p>使用===全等运算符在比较时如果类型不同直接返回false</p><h3 id="类型转换" tabindex="-1"><a class="header-anchor" href="#类型转换"><span>类型转换</span></a></h3><h4 id="将字符类型转换为整形" tabindex="-1"><a class="header-anchor" href="#将字符类型转换为整形"><span>将字符类型转换为整形</span></a></h4><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>paseInt(string s)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>在转换时会从左到右依次进行匹配,如果遇到一个不是数字的字符就会停下不会再转换了 如果开头就是一个非数字的字符就会返回nan</p><p>因此</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>paseInt(&quot;12a25&quot;);    //12</span></span>
<span class="line"><span>paseInt(&quot;a12&quot;);    //nan</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="其他类型转为boolean" tabindex="-1"><a class="header-anchor" href="#其他类型转为boolean"><span>其他类型转为boolean</span></a></h4><ul><li>Number：0和NaN为false，其他均转为true。</li><li>String：空字符串为false，其他均转为true。</li><li>Null 和 undefined：均转为false</li></ul><h1 id="定义函数" tabindex="-1"><a class="header-anchor" href="#定义函数"><span>定义函数</span></a></h1><p>在调用函数时传入参数比形参多也是不会报错的,它只会去前几个值作为参数</p><h4 id="function声明" tabindex="-1"><a class="header-anchor" href="#function声明"><span>function声明</span></a></h4><p>通过<code>function</code>关键字定义函数,函数和python一样形参都不需要指定返回值,返回值也不需要显式声明</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>function funcName(a,b){}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h4 id="var定义" tabindex="-1"><a class="header-anchor" href="#var定义"><span>var定义</span></a></h4><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>var funcName=function(a,b){}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h3 id="匿名函数" tabindex="-1"><a class="header-anchor" href="#匿名函数"><span>匿名函数</span></a></h3><p>匿名函数无法直接调用</p><h4 id="函数表达式调用" tabindex="-1"><a class="header-anchor" href="#函数表达式调用"><span>函数表达式调用</span></a></h4><p>将匿名函数赋值给一个变量，并且通过变量名称进行调用我们将这个称为函数表达式</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>let fn=function(){</span></span>
<span class="line"><span>	//函数体</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="立即执行调用" tabindex="-1"><a class="header-anchor" href="#立即执行调用"><span>立即执行调用</span></a></h4><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>(function(){/函数体})();</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h1 id="对象" tabindex="-1"><a class="header-anchor" href="#对象"><span>对象</span></a></h1><h2 id="数组" tabindex="-1"><a class="header-anchor" href="#数组"><span>数组</span></a></h2><p>有两种定义方式</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>//var 变量名=new Array(元素列表);</span></span>
<span class="line"><span>var arr = new Array(1,2,3,4);</span></span>
<span class="line"><span></span></span>
<span class="line"><span>//var 变量名=[元素列表];</span></span>
<span class="line"><span>var arr=[1,2,3,4];</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="属性" tabindex="-1"><a class="header-anchor" href="#属性"><span>属性</span></a></h4><ul><li>length : 数组的长度</li></ul><h4 id="成员函数" tabindex="-1"><a class="header-anchor" href="#成员函数"><span>成员函数</span></a></h4><ul><li>forEach : 遍历整个数组 forEach在遍历时值遍历有值的元素,没值的自动跳过,使用for循环可以都遍历出来</li><li>push : 在末尾添加元素</li><li>splice : 删除,有两个参数,第一个参数是开始删除元素的索引,第二个参数是删除元素的个数</li></ul><h2 id="匿名函数-1" tabindex="-1"><a class="header-anchor" href="#匿名函数-1"><span>匿名函数</span></a></h2><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>(形参列表)=&gt;{函数体}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h2 id="字符串" tabindex="-1"><a class="header-anchor" href="#字符串"><span>字符串</span></a></h2><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>var 变量名=new String(&quot;&quot;);</span></span>
<span class="line"><span>var 变量名=&quot;&quot;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>定义字符串有两种方式,在定义的时候使用双引号和单引号没有区别</p><h3 id="属性-1" tabindex="-1"><a class="header-anchor" href="#属性-1"><span>属性</span></a></h3><p>length : 字符串长度</p><h3 id="成员函数-1" tabindex="-1"><a class="header-anchor" href="#成员函数-1"><span>成员函数</span></a></h3><p><code>charAt(index)</code>返回指定位置的字符 <code>indexOf(str)</code>检索字符串str在字符串中的索引 <code>trim()</code>去除字符串两边的空格返回去除空格后的字符串,并不会更改原字符串 <code>substring()</code>提取字符串中两个指定的索引号之间的字符。左闭右开</p><h2 id="自定义类型" tabindex="-1"><a class="header-anchor" href="#自定义类型"><span>自定义类型</span></a></h2><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>var 对象名={</span></span>
<span class="line"><span>	属性名1:属性值1,</span></span>
<span class="line"><span>	属性名2:属性值2,</span></span>
<span class="line"><span>	属性名3：属性值3,</span></span>
<span class="line"><span>	函数名称:function(形参列表){}</span></span>
<span class="line"><span>};</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>相比于其他语言,js的语法更自由还可以给对象增加或删除属性</p><p>添加数据</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>对象名.新属性名=新值;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>删除数据</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>delete 对象名.属性名;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>调用成员函数</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>对象名.函数名();</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>自定义类型获取数据有两种方式</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>对象名.属性名;</span></span>
<span class="line"><span>对象名[&#39;属性名&#39;]</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>使用for in循环获取到的属性字段是使用引号引用的字符串字段,因此可以使用方括号和for循环来遍历对象</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>for(let i int obj){</span></span>
<span class="line"><span>	console.log(obj[i])</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h1 id="基本数据类型和引用数据类型" tabindex="-1"><a class="header-anchor" href="#基本数据类型和引用数据类型"><span>基本数据类型和引用数据类型</span></a></h1><p>简单类型又叫做基本数据类型或者值类型，复杂类型又叫做引用类型。</p><ul><li>值类型：简单数据类型/基本数据类型，在存储时变量中存储的是值本身，因此叫做值类型 string，number，boolean，undefined，null</li><li>引用类型：复杂数据类型，在存储时变量中存储的仅仅是地址（引用），因此叫做引用数据类型.通过 new 关键字创建的对象（系统对象、自定义对象），如Object、Array、Date等</li></ul><p>const修饰的基本数据类型无法修改数据,但引用数据类型可以修改数据,这是因为const修饰的是指针指向的地址是不变的</p><h2 id="json" tabindex="-1"><a class="header-anchor" href="#json"><span>JSON</span></a></h2><p>js中的json的键必须使用双引号引起来 是使用字符串存储的</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>var 变量名=&#39;{&quot;key1&quot;:value1,&quot;key2&quot;:value2}&#39;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h4 id="json和js对象的转换" tabindex="-1"><a class="header-anchor" href="#json和js对象的转换"><span>json和js对象的转换</span></a></h4><p>将字符串str转换为js对象,返回转换成的对象,原字符串不做更改</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>JSON.parse(str)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>将js对象转换为json字符串,返回转换后的字符串,原对象不做更改</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>JSON.stringify(jsobject)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div>`,103)]))}const h=e(l,[["render",d]]),p=JSON.parse('{"path":"/front/js/1/","title":"1 JavaScript概述","lang":"zh-CN","frontmatter":{"title":"1 JavaScript概述","createTime":"2025/04/05 12:12:26","permalink":"/front/js/1/"},"readingTime":{"minutes":6.04,"words":1812},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/前端/JavaScript/1 JavaScript概述.md","headers":[]}');export{h as comp,p as data};
